import{_ as e,c as i,o as l,ae as t}from"./chunks/framework.CMFi8ROq.js";const u=JSON.parse('{"title":"微前端","description":"","frontmatter":{},"headers":[],"relativePath":"article/微前端.md","filePath":"article/微前端.md","lastUpdated":null}'),o={name:"article/微前端.md"};function r(n,a,h,s,d,p){return l(),i("div",null,a[0]||(a[0]=[t('<h1 id="微前端" tabindex="-1">微前端 <a class="header-anchor" href="#微前端" aria-label="Permalink to &quot;微前端&quot;">​</a></h1><h2 id="什么是微前端" tabindex="-1">什么是微前端 <a class="header-anchor" href="#什么是微前端" aria-label="Permalink to &quot;什么是微前端&quot;">​</a></h2><p>微前端（Micro Frontends）架构可以被理解为“前端领域的微服务”。它的核心思想是：将一个庞大、复杂的单体前端应用 拆分为多个独立开发、独立测试、独立部署的小型前端应用，最后通过一个“容器应用”（Main/Host App）将它们集成在一 起展示给用户。</p><h5 id="微前端解决的问题" tabindex="-1">微前端解决的问题 <a class="header-anchor" href="#微前端解决的问题" aria-label="Permalink to &quot;微前端解决的问题&quot;">​</a></h5><p>微前端方案主要是为了解决传统单体前端（Monolithic Frontend）在复杂应用中存在的问题。</p><ol><li><p><strong>技术栈隔离</strong>：</p><p>单体应用一旦选定 React 或 Vue，后续所有模块都必须跟随。微前端允许不同子应用使用不同的技术栈（React, Vue, Angular 甚至原生 JS）。</p></li><li><p><strong>代码解耦和风险隔离</strong>：</p><p>在单体应用中，修改一个角落的全局样式或变量，可能导致另一个模块崩溃。微前端通过**沙箱隔离（Sandbox）**实现了逻辑和样式的物理/逻辑隔离。这种隔离使得 一个微应用的故障不会影响整个系统，提高了系统的稳定性和可靠性。</p></li><li><p><strong>发布流水线拥堵</strong>：</p><p>单体应用哪怕只改一个错别字，也要全量编译发布，耗时长且风险高。微前端支持独立发布，子应用上线无需通知主应用。</p></li><li><p><strong>团队协作</strong>：</p><p>对于庞大的单体应用，代码的合并、构建、测试对于团队来讲都是灾难。微前端让团队可以按业务功能横向拆分，每个团队负责自己的子应用。</p></li></ol><h5 id="微前端的主要优势" tabindex="-1">微前端的主要优势 <a class="header-anchor" href="#微前端的主要优势" aria-label="Permalink to &quot;微前端的主要优势&quot;">​</a></h5><ol><li>技术无关性：每个团队可以选择最适合业务场景的工具。</li><li>快速增量升级：可以在不重构整个应用的情况下，用新技术开发新功能，或者逐步替换旧模块（如：主应用 React，新功能用 Vue 3）。</li><li>独立开发与部署：每个子应用由独立团队负责，按照团队的节奏迭代、部署。</li><li>高复用性：子应用可以像组件一样，被集成到不同的业务系统中。</li><li>强隔离性：一个子应用崩溃不会导致整个门户挂掉，容错性更高。</li></ol><h5 id="微前端的应用场景" tabindex="-1">微前端的应用场景 <a class="header-anchor" href="#微前端的应用场景" aria-label="Permalink to &quot;微前端的应用场景&quot;">​</a></h5><p>虽然微前端很强大，但它也带来了首屏加载慢（多次资源请求）和管理复杂度增加的问题。因此，它通常适用于以下场景：</p><ol><li>超大型项目：由不同的团队开发、共同构建的应用，如企业级的 ERP、CRM、工业软件解决方案等。</li><li>老项目重构：使用新技术去开发新功能，而旧项目又不能直接扔掉，可以使用微前端进行“渐进式”迁移。</li></ol><p>综上所述：微前端并不是“让应用跑得更快”的技术，它是“让团队协作和代码维 护不随着应用规模扩大而崩盘”的架构方案。如果你的项目只有几个人维护，业务简单，强行上微前端只会增加“架构负担”。</p><h2 id="微前端沙箱原理" tabindex="-1">微前端沙箱原理 <a class="header-anchor" href="#微前端沙箱原理" aria-label="Permalink to &quot;微前端沙箱原理&quot;">​</a></h2><p>微前端架构中最具技术含量的核心：如何让多个独立运行的应用在同一个浏览器页面里“互不干扰”地和平共处。</p><p>在微前端中，隔离主要分为两个战场：样式隔离和JS 沙箱隔离。</p><h5 id="样式隔离" tabindex="-1">样式隔离 <a class="header-anchor" href="#样式隔离" aria-label="Permalink to &quot;样式隔离&quot;">​</a></h5><p>如果子应用 A 定义了 .title { color: red; }，而子应用 B 也有一个 .title 且希望它是蓝色的，后加载的样式就会覆盖掉先加载的。</p><p>常见的解决方案：</p><ol><li><p>Shadow DOM (最硬核的隔离)：</p><p>利用浏览器原生的 Shadow DOM API，将子应用挂载在 Shadow Root 下。这样 CSS 永远不会逃逸出这个容器。 缺点： 由于绝大多数 UI 组件库会把弹窗挂载到 <code>body</code> 下， 而 shadow DOM 内部 CSS 无法影响到外部样式，导致挂载位置出错。</p></li><li></li></ol><h5 id="js-沙箱隔离" tabindex="-1">JS 沙箱隔离 <a class="header-anchor" href="#js-沙箱隔离" aria-label="Permalink to &quot;JS 沙箱隔离&quot;">​</a></h5><h2 id="微前端方案-qiankun-乾坤" tabindex="-1">微前端方案：qiankun（乾坤） <a class="header-anchor" href="#微前端方案-qiankun-乾坤" aria-label="Permalink to &quot;微前端方案：qiankun（乾坤）&quot;">​</a></h2><p><a href="https://qiankun.umijs.org/zh" target="_blank" rel="noreferrer">qiankun</a> 是基于 single-spa 进行的深度二次封装，解决了 single-spa 过于底层、无沙箱机制、需要手动处理资源加载的痛点。</p><h3 id="底层原理" tabindex="-1">底层原理 <a class="header-anchor" href="#底层原理" aria-label="Permalink to &quot;底层原理&quot;">​</a></h3><p>qiankun 的核心并非从零开发，而是基于两个关键库构建的：</p><ol><li>single-spa：负责路由匹配和应用状态切换（解决“什么时候加载哪个应用”的问题）。</li><li>import-html-entry：负责动态加载和处理 HTML、JS 和 CSS 资源（解决“如何把远程代码拉回来并运行”的问题）。</li></ol><p>在此基础上，qiankun 补全了微前端最核心的两个能力：沙箱隔离（Sandbox） 和 应用间通信（Communication）。</p><h2 id="微前端方案-wujie-无界" tabindex="-1">微前端方案：wujie（无界） <a class="header-anchor" href="#微前端方案-wujie-无界" aria-label="Permalink to &quot;微前端方案：wujie（无界）&quot;">​</a></h2><h3 id="使用" tabindex="-1">使用 <a class="header-anchor" href="#使用" aria-label="Permalink to &quot;使用&quot;">​</a></h3><h3 id="底层原理-1" tabindex="-1">底层原理 <a class="header-anchor" href="#底层原理-1" aria-label="Permalink to &quot;底层原理&quot;">​</a></h3>',29)]))}const q=e(o,[["render",r]]);export{u as __pageData,q as default};
